import{_ as e,o as s,c as n,a3 as i}from"./chunks/framework.CRbjHCyB.js";const u=JSON.parse('{"title":"增量编译","description":"","frontmatter":{},"headers":[],"relativePath":"zh/clice/design/incremental-parse.md","filePath":"zh/clice/design/incremental-parse.md"}'),l={name:"zh/clice/design/incremental-parse.md"};function p(t,a,o,r,c,d){return s(),n("div",null,[...a[0]||(a[0]=[i(`<h1 id="增量编译" tabindex="-1">增量编译 <a class="header-anchor" href="#增量编译" aria-label="Permalink to &quot;增量编译&quot;">​</a></h1><h2 id="背景" tabindex="-1">背景 <a class="header-anchor" href="#背景" aria-label="Permalink to &quot;背景&quot;">​</a></h2><p>C++ 的 <code>#include</code> 是文本替换——预处理器将被包含的头文件内容原样插入到源文件中。一个只有几十行用户代码的源文件，经过 <code>#include</code> 展开后，可能膨胀到数万行甚至更多。例如，仅 <code>#include &lt;vector&gt;</code> 一条指令就会引入数千行标准库代码，如果再加上项目自身的头文件，展开后的代码量可以轻松超过十万行。</p><p>语言服务器需要在每次用户编辑后重新编译文件，以提供最新的诊断、补全和语义信息。如果每次都完整编译这十万行代码，延迟会达到数秒，显然不可接受。</p><p>但观察用户的实际编辑行为，会发现一个关键特征：文件头部的 <code>#include</code> 区域很少变化，真正频繁变化的只是底部的用户代码。在一次典型的编辑会话中，用户可能修改了上百次代码，但 <code>#include</code> 区域一次也没动过。</p><div class="language-cpp vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">cpp</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">#include</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &lt;vector&gt;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">#include</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &lt;string&gt;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">#include</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &lt;map&gt;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">#include</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;project/config.h&quot;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">#include</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;project/logging.h&quot;</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// ── preamble ↑ 变化慢，编译结果可以缓存 ──</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// ── 用户代码 ↓ 变化快，每次需要重新编译 ──</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">void</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> process</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">const</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> std</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">::</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">vector</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">std</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">::</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">string</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&amp;</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;"> data</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) {</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    // ...</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>基于这个观察，C++ 语言服务器普遍采用 <strong>preamble 分离</strong>策略：将文件分为头部的 preamble（预处理指令区域）和剩余的用户代码。Preamble 编译为预编译头文件（PCH）并缓存，后续编译直接加载 PCH，只重新处理用户代码。这样每次编辑后的重编译只涉及几十行到几百行代码，延迟通常可以控制在一秒以内。</p><p>clangd 也采用了这一策略，但在失效检测和生命周期管理方面存在一些设计层面的不足：</p><ul><li><p><strong>内存占用高</strong>。clangd 将 preamble 的编译产物保留在进程内存中。对于大型项目，多个打开文件的 preamble AST 会消耗大量内存，长时间运行后内存占用持续增长（clangd <a href="https://github.com/clangd/clangd/issues/251" target="_blank" rel="noreferrer">#251</a>、<a href="https://github.com/clangd/clangd/issues/115" target="_blank" rel="noreferrer">#115</a>）。</p></li><li><p><strong>崩溃后 PCH 文件泄漏</strong>。clangd 使用临时文件存储磁盘上的 PCH。崩溃时 RAII 清理无法执行，临时文件残留在 <code>/tmp</code> 中。在多用户服务器上，累积的泄漏文件会耗尽 <code>/tmp</code> 空间（clangd <a href="https://github.com/clangd/clangd/issues/209" target="_blank" rel="noreferrer">#209</a>、<a href="https://github.com/clangd/clangd/issues/255" target="_blank" rel="noreferrer">#255</a>）。</p></li><li><p><strong>失效检测不够精确</strong>。当头文件被 touch 但内容未变时（常见于构建工具的依赖扫描、版本控制的分支切换），仅靠修改时间（mtime）判断会导致不必要的 PCH 重建。在大型项目中，这种误报造成的重复构建会明显影响编辑体验。</p></li><li><p><strong>重启后需要冷启动</strong>。PCH 不跨会话持久化，服务器重启后需要为所有打开的文件重新构建 PCH。</p></li></ul><p>clice 针对这些问题重新设计了增量编译机制：磁盘持久化的内容寻址 PCH 存储、两层失效检测、拉取式编译模型和 preamble 完整性检测。</p><h2 id="设计" tabindex="-1">设计 <a class="header-anchor" href="#设计" aria-label="Permalink to &quot;设计&quot;">​</a></h2><p>增量编译围绕四个核心概念组织：preamble 分离定义了&quot;缓存什么&quot;，两层失效检测定义了&quot;何时重建&quot;，拉取式编译定义了&quot;何时触发&quot;，内容寻址存储定义了&quot;怎么存&quot;。</p><h3 id="preamble-分离" tabindex="-1">Preamble 分离 <a class="header-anchor" href="#preamble-分离" aria-label="Permalink to &quot;Preamble 分离&quot;">​</a></h3><p>Preamble 是源文件头部由预处理指令（<code>#include</code>、<code>#define</code>、<code>#pragma</code> 等）和模块声明（<code>module;</code>）组成的区域。Preamble 的结束位置由一个字节偏移量（bound）标识——第一行非预处理内容之前的字节位置。</p><p>Preamble 编译为 PCH 文件后缓存在磁盘上。后续编译加载 PCH 后，只需要处理 bound 之后的用户代码。如果 preamble 为空（bound 为零），则不需要 PCH，直接跳过整个 PCH 流程。</p><p><code>PCHState</code> 是 PCH 在缓存中的条目，包含：</p><ul><li>PCH 文件在磁盘上的路径</li><li>preamble 内容的哈希值</li><li>preamble 的字节边界（bound）</li><li>依赖快照（<code>DepsSnapshot</code>，见下文）</li><li>PCH 中提取的 DocumentLink 信息（<code>#include</code> 指令的位置和目标，供编辑器显示可点击链接）</li></ul><h3 id="两层失效检测" tabindex="-1">两层失效检测 <a class="header-anchor" href="#两层失效检测" aria-label="Permalink to &quot;两层失效检测&quot;">​</a></h3><p>PCH 缓存了 preamble 中所有被 <code>#include</code> 的头文件的预处理结果。当任何一个依赖头文件的内容发生变化时，PCH 就已过时，需要重建。问题在于如何精确判断&quot;内容是否真的变了&quot;。</p><p>最直接的方案是检查文件修改时间（mtime）：如果所有依赖文件的 mtime 都不晚于 PCH 的构建时间，说明没有文件被修改过。这种检查只需 <code>stat</code> 系统调用，非常快。但 mtime 检查会产生误报：构建工具的依赖扫描、版本控制的分支切换、编辑器的自动保存等操作都会更新 mtime 而不改变文件内容。</p><p>另一个方案是直接比较文件内容的哈希值：每次检查时重新计算所有依赖文件的哈希，与构建时记录的哈希比较。这种方案完全精确，但需要读取和计算所有依赖文件的内容。一个典型的 C++ 文件可能依赖数百个头文件，每次检查都全量哈希的 I/O 开销不可忽视。</p><p>clice 将两者结合为两层检测策略：</p><ul><li><strong>第一层（mtime 快速筛选）</strong>：遍历所有依赖文件，比较每个文件的 mtime 与 PCH 的构建时间戳。如果所有 mtime 都不晚于构建时间戳，PCH 有效，直接复用。</li><li><strong>第二层（内容哈希精确验证）</strong>：对第一层标记为&quot;可能已修改&quot;的文件（mtime 晚于构建时间戳），重新计算其 xxh3 内容哈希，与构建时记录的哈希比较。只有哈希不一致时才触发重建。</li></ul><p>第一层过滤掉了绝大多数未变化的文件（常态路径），第二层消除了 mtime 误报（构建工具 touch、VCS checkout 等场景）。两层结合的效果是：只有依赖文件的内容真正发生变化时才重建 PCH。</p><p><code>DepsSnapshot</code> 是两层检测的基础数据结构，在 PCH 构建完成时捕获。它记录所有依赖文件的路径标识、内容哈希和构建时间戳。</p><h3 id="拉取式编译" tabindex="-1">拉取式编译 <a class="header-anchor" href="#拉取式编译" aria-label="Permalink to &quot;拉取式编译&quot;">​</a></h3><p>clice 采用拉取式（pull-based）编译模型：编译不在文件变更时立即触发，而是在功能请求（hover、补全、语义高亮等）需要最新 AST 时按需触发。</p><p>当用户编辑文件时（<code>didChange</code>），主进程只更新内存中的文件内容并标记 AST 为脏（<code>ast_dirty</code>），不启动任何编译。当功能请求到达时，编译服务检查 AST 是否脏或是否因外部文件变化而过时，如果需要重编译，则先确保 PCH 和模块依赖就绪，再将编译任务发送到工作进程。</p><p>这种模型的好处是避免了用户快速连续输入时的无效编译。用户每秒可能触发十几次 <code>didChange</code>，但只有当鼠标悬停、请求补全等实际需要编译结果时，才执行一次编译。</p><blockquote><p>注意&quot;外部文件变化&quot;和&quot;用户编辑&quot;是两条独立的脏标记路径。用户编辑通过 <code>didChange</code> 标记 <code>ast_dirty</code>；外部文件变化（如依赖的头文件被修改）通过两层失效检测在编译前动态发现。</p></blockquote><h3 id="内容寻址-pch-存储" tabindex="-1">内容寻址 PCH 存储 <a class="header-anchor" href="#内容寻址-pch-存储" aria-label="Permalink to &quot;内容寻址 PCH 存储&quot;">​</a></h3><p>PCH 文件在磁盘上以 preamble 内容的哈希值命名（如 <code>a3f7e8c1d2b4f6e9.pch</code>），实现内容寻址。这带来两个好处：</p><ul><li><strong>磁盘共享</strong>：具有相同 preamble 内容的不同文件自然共享同一个 PCH 磁盘文件，无需额外的去重逻辑。</li><li><strong>跨会话持久化</strong>：PCH 缓存的元数据（路径、哈希、边界、依赖快照）序列化到磁盘上的 <code>cache.json</code> 文件。服务器重启时加载这些元数据，通过两层失效检测验证 PCH 是否仍然有效，避免冷启动时重建所有 PCH。</li></ul><p>当 preamble 内容变化时，新的 PCH 使用不同的哈希命名，旧文件成为孤立文件。清理机制定期回收超过一定期限未使用的孤立 PCH 文件。</p><h2 id="实现" tabindex="-1">实现 <a class="header-anchor" href="#实现" aria-label="Permalink to &quot;实现&quot;">​</a></h2><h3 id="preamble-边界计算" tabindex="-1">Preamble 边界计算 <a class="header-anchor" href="#preamble-边界计算" aria-label="Permalink to &quot;Preamble 边界计算&quot;">​</a></h3><p>Preamble 的边界通过词法扫描确定：使用项目的 <code>Lexer</code> 从文件开头逐行扫描，识别以 <code>#</code> 开头的预处理指令和 <code>module;</code> 全局模块片段声明。遇到第一行非预处理内容时停止，返回此时的字节偏移作为边界。</p><p>这种基于词法的检测不需要启动完整的预处理器，速度非常快。</p><h3 id="preamble-完整性检查" tabindex="-1">Preamble 完整性检查 <a class="header-anchor" href="#preamble-完整性检查" aria-label="Permalink to &quot;Preamble 完整性检查&quot;">​</a></h3><p>在触发 PCH 重建之前，需要检查 preamble 是否在语法上完整。两种典型的不完整状态：</p><div class="language-cpp vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">cpp</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">#include</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;lib</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">          // 引号未闭合，用户正在输入文件名</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">import std.core</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">        // 缺少分号，用户正在输入模块声明</span></span></code></pre></div><p>如果在不完整的 preamble 上构建 PCH，会产生一个包含错误预处理状态的 PCH 文件。后续加载这个错误 PCH 的编译会看到大量虚假错误。因此，当检测到 preamble 不完整时，延迟重建，继续使用旧的 PCH（如果存在）。</p><h3 id="pch-构建流水线" tabindex="-1">PCH 构建流水线 <a class="header-anchor" href="#pch-构建流水线" aria-label="Permalink to &quot;PCH 构建流水线&quot;">​</a></h3><p>当编译请求需要 PCH 时，按以下流程处理：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>计算 preamble 边界和哈希</span></span>
<span class="line"><span>         │</span></span>
<span class="line"><span>         ▼</span></span>
<span class="line"><span>   ┌─ 缓存命中？──── 是 → 复用缓存的 PCH</span></span>
<span class="line"><span>   │     │</span></span>
<span class="line"><span>   │    否</span></span>
<span class="line"><span>   │     │</span></span>
<span class="line"><span>   │     ▼</span></span>
<span class="line"><span>   │  preamble 完整？── 否 → 延迟重建，沿用旧 PCH</span></span>
<span class="line"><span>   │     │</span></span>
<span class="line"><span>   │    是</span></span>
<span class="line"><span>   │     │</span></span>
<span class="line"><span>   │     ▼</span></span>
<span class="line"><span>   │  有其他协程正在构建？── 是 → 等待构建完成，使用结果</span></span>
<span class="line"><span>   │     │</span></span>
<span class="line"><span>   │    否</span></span>
<span class="line"><span>   │     │</span></span>
<span class="line"><span>   │     ▼</span></span>
<span class="line"><span>   │  发送到无状态工作进程构建 PCH</span></span>
<span class="line"><span>   │     │</span></span>
<span class="line"><span>   │     ▼</span></span>
<span class="line"><span>   └─ 更新缓存，捕获依赖快照</span></span></code></pre></div><p>缓存命中的条件有两个：preamble 哈希与缓存一致（preamble 内容没变），且两层失效检测通过（依赖文件内容没变）。两个条件必须同时满足。</p><p>PCH 构建由无状态工作进程执行（详见<a href="./multi-process">多进程架构</a>）。工作进程使用 Clang 的 Preamble 编译模式，只处理 bound 之前的 preamble 部分。构建完成后返回 PCH 文件路径和依赖文件列表。</p><h3 id="并发构建序列化" tabindex="-1">并发构建序列化 <a class="header-anchor" href="#并发构建序列化" aria-label="Permalink to &quot;并发构建序列化&quot;">​</a></h3><p>多个功能请求可能同时触发同一文件的 PCH 构建。<code>PCHState</code> 中包含一个共享事件（<code>building</code>）：第一个发起构建的协程设置这个事件，后续协程发现事件存在时等待其完成，然后使用构建结果。这确保同一文件的 PCH 只构建一次。</p><h3 id="依赖快照的时序保证" tabindex="-1">依赖快照的时序保证 <a class="header-anchor" href="#依赖快照的时序保证" aria-label="Permalink to &quot;依赖快照的时序保证&quot;">​</a></h3><p><code>DepsSnapshot</code> 的构建时间戳（<code>build_at</code>）在计算文件哈希<strong>之前</strong>获取。这个顺序确保了不存在遗漏修改的时间窗口：</p><p>如果一个文件在哈希计算过程中被修改，它的 mtime 会晚于 <code>build_at</code>。下次两层检测时，第一层会将这个文件标记为&quot;可能已修改&quot;，第二层会重新计算哈希并发现变化。</p><p>如果反过来先计算哈希再获取时间戳，就可能出现这样的窗口：文件在哈希计算和时间戳获取之间被修改，但 mtime 不晚于 <code>build_at</code>，导致修改被遗漏。</p><h3 id="整体编译流程" tabindex="-1">整体编译流程 <a class="header-anchor" href="#整体编译流程" aria-label="Permalink to &quot;整体编译流程&quot;">​</a></h3><p>当功能请求到达时，编译流水线按以下顺序执行：</p><ol><li>检查 AST 是否已缓存且未过时——是则直接复用</li><li>如果使用了 C++20 模块，先确保模块依赖就绪（详见<a href="./module-graph">模块编译</a>）</li><li>确保 PCH 就绪</li><li>将编译任务发送到有状态工作进程，附带 PCH 路径和模块文件路径</li><li>工作进程加载 PCH 后只编译 preamble 之后的用户代码</li></ol><p>AST 的依赖文件（preamble 之后的 <code>#include</code>）同样通过 <code>DepsSnapshot</code> 跟踪，使用相同的两层失效检测。即使用户没有编辑当前文件，如果其依赖的头文件在磁盘上被修改，下次功能请求时也会触发重编译。</p><h3 id="与编译上下文的交互" tabindex="-1">与编译上下文的交互 <a class="header-anchor" href="#与编译上下文的交互" aria-label="Permalink to &quot;与编译上下文的交互&quot;">​</a></h3><p>对于非自包含头文件，编译上下文系统会合成一个前缀文件，通过 <code>-include</code> 注入到编译参数中（详见<a href="./compilation-context">编译上下文</a>）。这个注入的前缀文件会被 Clang 在 preamble 编译阶段处理，因此自然地被 PCH 缓存覆盖。PCH 的构建流水线对源文件和头文件的处理是统一的。</p><h3 id="缓存持久化" tabindex="-1">缓存持久化 <a class="header-anchor" href="#缓存持久化" aria-label="Permalink to &quot;缓存持久化&quot;">​</a></h3><p>PCH 和 PCM 的缓存元数据通过 <code>cache.json</code> 文件持久化到磁盘。每次成功构建后更新，服务器启动时加载。写入采用先写临时文件再原子重命名的模式，避免写入过程中崩溃导致文件损坏。</p><p>启动时加载缓存后，所有 PCH 条目通过两层失效检测验证有效性。过时的条目会在下次编译时自动重建，无需特殊的缓存一致性恢复逻辑。</p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><ul><li><p><strong>为什么用两层检测，而不是只用内容哈希？</strong> 内容哈希虽然精确，但需要读取所有依赖文件的内容。一个典型的 C++ 文件可能依赖数百个头文件，每次检查都全量哈希的 I/O 开销不可忽视。mtime 快速筛选将需要哈希的文件数量缩减到&quot;自上次构建以来被 touch 过的文件&quot;，在常态路径下通常为零。</p></li><li><p><strong>为什么每次都完全重建 PCH？能否增量更新？</strong> Clang 支持链式 PCH（chained PCH）：将 preamble 中的每条 <code>#include</code> 构建为独立的 PCH 链节，每个链节依赖前一个链节的编译产物。当用户在 preamble 末尾新增一条 <code>#include</code> 时，只需要在已有链的末尾追加一个链节，而不是重建整个 preamble。基准测试表明（PR <a href="https://github.com/ykiko/clice/pull/405" target="_blank" rel="noreferrer">#405</a>），对于 70 个 C++ 标准库头文件的 preamble，增量追加一条 <code>#include</code> 只需约 36ms，而整体重建需要约 1230ms（35 倍加速）。链式 PCH 的 AST 加载延迟几乎不受影响（+2% ~ +6%）。clice 计划引入链式 PCH 来优化增量重建性能，目前尚在实验阶段。</p></li><li><p><strong>为什么采用拉取式编译而不是推送式？</strong> 关键原因在于 clice 将所有文件的 PCH 持久化到磁盘上，缓存的文件数量远多于 clangd 的内存模型（clangd 通过 LRU 策略只保留少量活跃文件的 preamble）。当一个头文件被修改时，可能有大量文件的 PCH 受到影响。如果采用推送式编译，就需要在头文件修改时立即重建所有受影响的 PCH，这个数量级是不可接受的。拉取式编译将重建延迟到功能请求到达时，只重建用户当前需要的那个文件的 PCH。由于 PCH 加载本身很快（见下一条），这种按需重建引入的延迟很小。</p></li><li><p><strong>磁盘 PCH 比内存 PCH 慢吗？</strong> 实际影响很小。Clang 的 PCH 加载使用 mmap 将文件映射到内存，避免了完整的读取拷贝。更重要的是，Clang 对 PCH 中的 AST 节点采用惰性反序列化——只有实际被引用的节点才会被反序列化，大部分 PCH 内容在编译过程中不会被访问。因此 PCH 的加载性能主要取决于二进制文件的映射方式，磁盘文件和内存缓冲区之间没有本质差异。而磁盘 PCH 带来的好处——跨重启持久化、不占用进程常驻内存、内容寻址共享——使得这个 trade-off 是值得的。</p></li></ul><h2 id="已知局限" tabindex="-1">已知局限 <a class="header-anchor" href="#已知局限" aria-label="Permalink to &quot;已知局限&quot;">​</a></h2><ul><li><p><strong>每文件独立缓存</strong>。PCH 缓存以文件的路径标识为键，即使两个文件具有完全相同的 preamble 内容，它们在缓存中也是独立的条目——各自执行失效检测和构建。虽然磁盘上的 PCH 文件通过内容寻址命名实现了共享，但缓存的元数据（依赖快照、构建状态等）没有共享。改进方向是以 preamble 内容哈希加编译标志为键，实现跨文件的缓存元数据共享。</p></li><li><p><strong>完全重建</strong>。任何一个依赖文件的内容变化都触发 PCH 的完全重建，无法做到只重建受影响的部分。改进方向是引入链式 PCH（见 FAQ），将重建范围限制在变化点之后的链节。</p></li><li><p><strong>编译标志不参与缓存键</strong>。PCH 的磁盘文件名和缓存查找都不考虑编译标志。当两个文件具有相同的 preamble 文本但不同的编译标志（如 <code>-D</code>）时，可能错误地共享 PCH。改进方向是将影响预处理的编译标志纳入缓存键。</p></li><li><p><strong>Preamble 完整性检查不完整</strong>。当前的完整性检查只覆盖了 <code>#include</code>/<code>import</code> 指令中的未闭合引号和缺失分号。其他类型的不完整编辑（如正在输入 <code>#define</code> 的值）不会被检测到。如果这类不完整的 preamble 被构建为 PCH，对后续编译的影响尚未充分测试。需要进一步研究 Clang 在处理不完整预处理指令时的行为，以确定是否需要扩展完整性检查的范围。</p></li><li><p><strong>头文件保存后不主动推送诊断更新</strong>。当前的纯拉取式模型下，用户保存一个头文件后，依赖该头文件的已打开源文件不会立即更新诊断——需要用户在源文件上触发操作（如 hover、编辑）才会通过两层失效检测发现变化并重编译。改进方向是在 <code>didSave</code> 时检查已打开的 session 是否受影响，为它们主动触发一次编译（混合推/拉模型）。</p></li></ul>`,66)])])}const g=e(l,[["render",p]]);export{u as __pageData,g as default};
